package io.github.cdimascio.dotenv;

import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;

import java.nio.file.Files;
import java.nio.file.Path;
import java.util.Arrays;
import java.util.Collections;
import java.util.Set;

import static org.junit.jupiter.api.Assertions.*;

public class DotenvBuilder_load_Test {

    @Test
    @DisplayName("TC01: Default load() with no entries applies no systemProperties and returns empty Dotenv")
    void test_TC01() throws Exception {
        // GIVEN: non-existing directory -> no file -> throwIfMissing=false leads to B1->B2 path, no entries loop
        Path dir = Files.createTempDirectory("nonexistent_dir");
        // ensure directory is empty and no .env
        DotenvBuilder builder = Dotenv.configure().directory(dir.toString()).ignoreIfMissing();
        // WHEN
        Dotenv dotenv = builder.load();
        // THEN: entries size 0 as no file and missing is ignored
        assertEquals(0, dotenv.entries().size());
    }

    @Test
    @DisplayName("TC02: Default load() with a single valid entry applies no systemProperties and returns one entry")
    void test_TC02() throws Exception {
        // GIVEN: one-line .env -> B1->B2 branch true (systemProperties=false), loop executes once
        Path dir = Files.createTempDirectory("envdir");
        Path envFile = dir.resolve(".env");
        Files.write(envFile, Collections.singletonList("KEY=VALUE"));
        DotenvBuilder builder = Dotenv.configure().directory(dir.toString()).filename(".env");
        // WHEN
        Dotenv dotenv = builder.load();
        // THEN: contains the single entry
        Set<DotenvEntry> entries = dotenv.entries();
        assertTrue(entries.contains(new DotenvEntry("KEY", "VALUE")));
        assertEquals(1, entries.size());
    }

    @Test
    @DisplayName("TC03: Default load() with multiple valid entries applies no systemProperties and returns all entries")
    void test_TC03() throws Exception {
        // GIVEN: two-line .env -> B1->B2 branch true, loop executes twice
        Path dir = Files.createTempDirectory("envdir2");
        Path envFile = dir.resolve(".env");
        Files.write(envFile, Arrays.asList("A=1", "B=2"));
        DotenvBuilder builder = Dotenv.configure().directory(dir.toString());
        // WHEN
        Dotenv dotenv = builder.load();
        // THEN: size=2 and correct values
        assertEquals(2, dotenv.entries().size());
        assertEquals("1", dotenv.get("A"));
        assertEquals("2", dotenv.get("B"));
    }

    @Test
    @DisplayName("TC04: load() with systemProperties=true skips setting via forEach and returns entries without altering System properties")
    void test_TC04() throws Exception {
        // GIVEN: one-line .env and systemProperties=true -> B0->B2 branch false (skip loop), ensure system remains unchanged
        System.clearProperty("X");
