        DotenvBuilder builder = Dotenv.configure().directory(dir.toString()).systemProperties();
        // WHEN
        Dotenv dotenv = builder.load();
        // THEN: System property X unchanged (null) and entry still present
        assertNull(System.getProperty("X"));
        assertTrue(dotenv.entries().contains(new DotenvEntry("X", "Y")));
    }

